import { Vex } from 'vex-sdk';
import OpenAI from 'openai';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

export const handler = async (event) => {
  const payload = JSON.parse(event.body);
  const run = payload.data.object;

  if (run.status === 'completed' && run.required_action?.type === 'submit_tool_outputs') {
    const messages = await openai.beta.threads.messages.list(run.thread_id);
    const output = messages.data[0].content[0].text?.value || '';

    const result = await vex.verify({
      input: run.assistant_id,
      output,
      policy: 'pci-dss-cardholder-data',
      context: { industry: 'fintech', sandbox: true }
    });

    if (!result.passed) {
      await openai.beta.threads.runs.submit(run.thread_id, {
        assistant_id: run.assistant_id,
        tool_outputs: [{ tool_call_id: 'pci_scan', output: JSON.stringify(result.failures) }]
      });
      return { statusCode: 200, body: 'Blocked: PCI violation' };
    }
  }
  return { statusCode: 200 };
};
